import axios from "axios";

const handleRegister = async () => {
  try {
    const res = await axios.post(
      "http://localhost:5000/api/auth/register",
      {
        email,
        password,
        role
      }
    );

    alert(res.data.message);
  } catch (err) {
    alert(err.response.data.message);
  }
};
